 38→
 39→/**
 40→ * Check prerequisites and display warnings
 41→ */
 42→function checkPrerequisites(): { warnings: string[]; suggestions: string[] } {
 43→  const warnings: string[] = [];
 44→  const suggestions: string[] = [];
 45→
 46→  // Check for gh CLI
 47→  if (!commandExists("gh")) {
 48→    warnings.push(
 49→      "GitHub CLI (gh) is not installed. Required for issue workflows.",
 50→    );
 51→    suggestions.push(`Install: ${getInstallHint("gh")}`);
 52→  } else if (!isGhAuthenticated()) {
 53→    warnings.push("GitHub CLI is not authenticated.");
 54→    suggestions.push("Run: gh auth login");
 55→  }
 56→
 57→  // Check for jq (optional)
 58→  if (!commandExists("jq")) {
 59→    suggestions.push(
 60→      `Optional: Install jq for faster JSON parsing (${getInstallHint("jq")})`,
 61→    );
 62→  }
 63→
 64→  return { warnings, suggestions };
 65→}
 66→
 67→interface InitOptions {
 68→  stack?: string;
 69→  yes?: boolean;
 70→  force?: boolean;
 71→  interactive?: boolean;
 72→  skipSetup?: boolean;
 73→  noSymlinks?: boolean;
 74→}
 75→
 76→/**
 77→ * Entries to add to .gitignore
 78→ */
 79→const GITIGNORE_ENTRIES = [
 80→  "",
 81→  "# Sequant runtime data (logs, settings)",
 82→  ".sequant/",
 83→];
 84→
 85→/**
 86→ * Update .gitignore with Sequant entries
 87→ */
 88→async function updateGitignore(): Promise<boolean> {
 89→  const gitignorePath = ".gitignore";
 90→  let content = "";
 91→
 92→  if (await fileExists(gitignorePath)) {
 93→    content = await readFile(gitignorePath);
 94→
 95→    // Check if already has .sequant/
 96→    if (content.includes(".sequant/")) {
 97→      return false; // Already configured
 98→    }
 99→  }
100→
101→  // Append entries
102→  const newContent =
103→    content.trimEnd() + "\n" + GITIGNORE_ENTRIES.join("\n") + "\n";
104→  await writeFile(gitignorePath, newContent);
105→  return true;
106→}
107→
108→/**
109→ * Log a default value being used in non-interactive mode
110→ */
111→function logDefault(label: string, value: string): void {
112→  console.log(chalk.blue(`📦 ${label}: ${value} (default)`));
113→}
