115→export async function initCommand(options: InitOptions): Promise<void> {
116→  // Show banner
117→  console.log(ui.banner());
118→  console.log(colors.success("\nInitializing Sequant...\n"));
119→
120→  // Determine if we should use interactive mode
121→  const useInteractive = shouldUseInteractiveMode(options.interactive);
122→  const skipPrompts = options.yes || !useInteractive;
123→
124→  // Show non-interactive mode message if applicable
125→  if (!useInteractive && !options.yes) {
126→    const reason = getNonInteractiveReason();
127→    console.log(
128→      chalk.yellow(
