/**
 * sequant init - Initialize Sequant in a project
 */

import chalk from "chalk";
import inquirer from "inquirer";
import { ui, colors } from "../lib/cli-ui.js";
import {
  detectStack,
  detectAllStacks,
  getStackConfig,
  detectPackageManager,
  getPackageManagerCommands,
  STACKS,
} from "../lib/stacks.js";
import { copyTemplates } from "../lib/templates.js";
import { createManifest } from "../lib/manifest.js";
import { saveConfig } from "../lib/config.js";
import { createDefaultSettings } from "../lib/settings.js";
import { detectAndSaveConventions } from "../lib/conventions-detector.js";
import { fileExists, ensureDir, readFile, writeFile } from "../lib/fs.js";
import {
  commandExists,
  isGhAuthenticated,
  getInstallHint,
} from "../lib/system.js";
import {
  shouldUseInteractiveMode,
  getNonInteractiveReason,
} from "../lib/tty.js";
import {
  checkAllDependencies,
  displayDependencyStatus,
  runSetupWizard,
  shouldRunSetupWizard,
} from "../lib/wizard.js";
import { saveStackConfig, type StackConfigFile } from "../lib/stack-config.js";

/**
 * Check prerequisites and display warnings
 */
function checkPrerequisites(): { warnings: string[]; suggestions: string[] } {
  const warnings: string[] = [];
  const suggestions: string[] = [];

  // Check for gh CLI
  if (!commandExists("gh")) {
    warnings.push(
      "GitHub CLI (gh) is not installed. Required for issue workflows.",
    );
    suggestions.push(`Install: ${getInstallHint("gh")}`);
  } else if (!isGhAuthenticated()) {
    warnings.push("GitHub CLI is not authenticated.");
    suggestions.push("Run: gh auth login");
  }

  // Check for jq (optional)
  if (!commandExists("jq")) {
    suggestions.push(
      `Optional: Install jq for faster JSON parsing (${getInstallHint("jq")})`,
    );
  }

  return { warnings, suggestions };
}

interface InitOptions {
  stack?: string;
  yes?: boolean;
  force?: boolean;
  interactive?: boolean;
  skipSetup?: boolean;
  noSymlinks?: boolean;
}

/**
 * Entries to add to .gitignore
 */
const GITIGNORE_ENTRIES = [
  "",
  "# Sequant runtime data (logs, settings)",
  ".sequant/",
];

/**
 * Update .gitignore with Sequant entries
 */
async function updateGitignore(): Promise<boolean> {
  const gitignorePath = ".gitignore";
  let content = "";

  if (await fileExists(gitignorePath)) {
    content = await readFile(gitignorePath);

    // Check if already has .sequant/
    if (content.includes(".sequant/")) {
      return false; // Already configured
    }
  }

  // Append entries
  const newContent =
    content.trimEnd() + "\n" + GITIGNORE_ENTRIES.join("\n") + "\n";
  await writeFile(gitignorePath, newContent);
  return true;
}

/**
 * Log a default value being used in non-interactive mode
 */
function logDefault(label: string, value: string): void {
  console.log(chalk.blue(`📦 ${label}: ${value} (default)`));
}

export async function initCommand(options: InitOptions): Promise<void> {
  // Show banner
  console.log(ui.banner());
  console.log(colors.success("\nInitializing Sequant...\n"));

  // Determine if we should use interactive mode
  const useInteractive = shouldUseInteractiveMode(options.interactive);
  const skipPrompts = options.yes || !useInteractive;

  // Show non-interactive mode message if applicable
  if (!useInteractive && !options.yes) {
    const reason = getNonInteractiveReason();
    console.log(
      chalk.yellow(
        `⚡ Non-interactive mode detected${reason ? ` (${reason})` : ""}`,
      ),
    );
    console.log(
      chalk.gray("   Using defaults. Use --interactive to force prompts.\n"),
    );
  }

  // Check dependencies and run setup wizard if needed
  const depCheckResult = checkAllDependencies();
  let wizardRemainingIssues: string[] = [];

  if (
    shouldRunSetupWizard({ skipSetup: options.skipSetup, yes: options.yes })
  ) {
    // Display dependency status
    displayDependencyStatus(depCheckResult);

    // Run wizard if there are missing required dependencies
    if (depCheckResult.hasMissing) {
      const wizardResult = await runSetupWizard(depCheckResult, {
        skipPrompts,
      });
      wizardRemainingIssues = wizardResult.remainingIssues;
    }
  } else if (options.skipSetup) {
    // User explicitly skipped - show brief status
    console.log(
      chalk.gray("Skipping dependency setup wizard (--skip-setup)\n"),
    );
  }

  // Fall back to legacy warning system for any remaining issues
  const { warnings, suggestions } = checkPrerequisites();

  // Only show warnings if wizard didn't already handle them or if there are remaining issues
  if (
    wizardRemainingIssues.length > 0 ||
    (options.skipSetup && warnings.length > 0)
  ) {
    if (wizardRemainingIssues.length > 0) {
      console.log(chalk.yellow("⚠️  Remaining setup issues:\n"));
      for (const issue of wizardRemainingIssues) {
        console.log(chalk.yellow(`   • ${issue}`));
      }
      console.log();
    } else if (warnings.length > 0) {
      console.log(chalk.yellow("⚠️  Prerequisites:\n"));
      for (const warning of warnings) {
        console.log(chalk.yellow(`   • ${warning}`));
      }
      for (const suggestion of suggestions.filter(
        (s) => !s.startsWith("Optional"),
      )) {
        console.log(chalk.gray(`     ${suggestion}`));
      }
      console.log();
    }
  }

  // Check if already initialized
  const configExists = await fileExists(".claude/settings.json");
  if (configExists && !options.force) {
    console.log(
      chalk.yellow(
        "⚠️  Sequant appears to be already initialized (.claude/settings.json exists)",
      ),
    );
    console.log(chalk.gray("   Use --force to reinitialize\n"));

    if (!skipPrompts) {
      const { proceed } = await inquirer.prompt([
        {
          type: "confirm",
          name: "proceed",
          message: "Continue anyway?",
          default: false,
        },
      ]);
      if (!proceed) {
        console.log(chalk.gray("Aborted."));
        return;
      }
    }
  }

  // Detect or prompt for stack
  let stack = options.stack;
  let additionalStacks: string[] = [];

  if (!stack) {
    // Check for multi-stack project in interactive mode
    const allDetectedStacks = !skipPrompts ? await detectAllStacks() : [];

    if (allDetectedStacks.length > 1 && !skipPrompts) {
      // Multi-stack project detected - show checkbox selection
      console.log(
        chalk.blue(
          `\n🔍 Detected ${allDetectedStacks.length} stacks in this project:`,
        ),
      );
      for (const ds of allDetectedStacks) {
        const location = ds.path ? ` (${ds.path}/)` : " (root)";
        console.log(
          chalk.gray(
            `   • ${STACKS[ds.stack]?.displayName || ds.stack}${location}`,
          ),
        );
      }
      console.log();

      // Multi-stack selection prompt
      const { selectedStacks } = await inquirer.prompt([
        {
          type: "checkbox",
          name: "selectedStacks",
          message: "Select stacks to include in your constitution:",
          choices: allDetectedStacks.map((ds) => ({
            name: `${STACKS[ds.stack]?.displayName || ds.stack}${ds.path ? ` (${ds.path}/)` : " (root)"}`,
            value: ds.stack,
            checked: true, // Pre-select all detected stacks
          })),
          validate: (answer: string[]) => {
            if (answer.length < 1) {
              return "You must select at least one stack.";
            }
            return true;
          },
        },
      ]);

      // First selected stack is the primary
      if (selectedStacks.length > 0) {
        stack = selectedStacks[0];
        additionalStacks = selectedStacks.slice(1);
      }

      // Confirm or change primary stack if multiple selected
      if (selectedStacks.length > 1) {
        const { primaryStack } = await inquirer.prompt([
          {
            type: "list",
            name: "primaryStack",
            message:
              "Which stack should be the primary? (determines dev URL and commands)",
            choices: selectedStacks.map((s: string) => ({
              name: STACKS[s]?.displayName || s,
              value: s,
            })),
          },
        ]);
        stack = primaryStack;
        additionalStacks = selectedStacks.filter(
          (s: string) => s !== primaryStack,
        );
      }
    } else {
      // Single stack detection (original behavior)
      const detected = await detectStack();
      if (detected && skipPrompts) {
        stack = detected;
        logDefault("Detected stack", stack);
      } else if (detected && !skipPrompts) {
        const { confirmedStack } = await inquirer.prompt([
          {
            type: "list",
            name: "confirmedStack",
            message: `Detected ${detected} project. Is this correct?`,
            choices: [
              { name: `Yes, use ${detected}`, value: detected },
              { name: "No, let me choose", value: null },
            ],
          },
        ]);
        stack = confirmedStack;
      }

      if (!stack && skipPrompts) {
        // No detection and skipping prompts: use generic as default
        stack = "generic";
        logDefault("Using stack", stack);
      } else if (!stack) {
        const { selectedStack } = await inquirer.prompt([
          {
            type: "list",
            name: "selectedStack",
            message: "Select your project stack:",
            choices: [
              { name: "Next.js / React", value: "nextjs" },
              { name: "Astro", value: "astro" },
              { name: "SvelteKit", value: "sveltekit" },
              { name: "Remix", value: "remix" },
              { name: "Nuxt", value: "nuxt" },
              { name: "Rust", value: "rust" },
              { name: "Python", value: "python" },
              { name: "Go", value: "go" },
              { name: "Generic (no stack-specific config)", value: "generic" },
            ],
          },
        ]);
        stack = selectedStack;
      }
    }
  }

  // Display selected stacks
  if (additionalStacks.length > 0) {
    console.log(chalk.blue(`\n📋 Primary Stack: ${stack}`));
    console.log(chalk.blue(`   Additional: ${additionalStacks.join(", ")}`));
  } else {
    console.log(chalk.blue(`\n📋 Stack: ${stack}`));
  }

  // Detect package manager
  const packageManager = await detectPackageManager();
  if (packageManager) {
    console.log(chalk.blue(`📦 Package Manager: ${packageManager}`));
  }

  // Get stack config for default dev URL
  const stackConfig = getStackConfig(stack!);
  let devUrl = stackConfig.devUrl;

  // Prompt for dev URL
  if (skipPrompts) {
    logDefault("Dev URL", devUrl);
  } else {
    const { inputDevUrl } = await inquirer.prompt([
      {
        type: "input",
        name: "inputDevUrl",
        message: "Development server URL:",
        default: devUrl,
      },
    ]);
    devUrl = inputDevUrl;
  }

  // Show what will be created
  console.log(chalk.gray("\nWill create:"));
  console.log(chalk.gray("  .claude/"));
  console.log(chalk.gray("  ├── skills/         (14 workflow skills)"));
  console.log(chalk.gray("  ├── hooks/          (pre/post tool hooks)"));
  console.log(chalk.gray("  ├── memory/         (constitution & context)"));
  console.log(chalk.gray("  └── settings.json   (hooks configuration)"));
  console.log(chalk.gray("  .sequant/"));
  console.log(chalk.gray("  ├── settings.json   (run preferences)"));
  console.log(chalk.gray("  └── logs/           (workflow run logs)"));
  console.log(chalk.gray("  scripts/dev/"));
  console.log(chalk.gray("  └── *.sh            (worktree helpers)"));

  if (!skipPrompts) {
    const { confirm } = await inquirer.prompt([
      {
        type: "confirm",
        name: "confirm",
        message: "Proceed with installation?",
        default: true,
      },
    ]);
    if (!confirm) {
      console.log(chalk.gray("Aborted."));
      return;
    }
  }

  // Create directories with spinner
  const dirSpinner = ui.spinner("Creating directories...");
  dirSpinner.start();
  await ensureDir(".claude/skills");
  await ensureDir(".claude/hooks");
  await ensureDir(".claude/memory");
  await ensureDir(".claude/.sequant");
  await ensureDir(".sequant/logs");
  await ensureDir("scripts/dev");
  dirSpinner.succeed("Created directories");

  // Update .gitignore
  const gitignoreUpdated = await updateGitignore();
  if (gitignoreUpdated) {
    ui.printStatus("success", "Updated .gitignore with Sequant entries");
  }

  // Save config with tokens
  const configSpinner = ui.spinner("Saving configuration...");
  configSpinner.start();
  const pmConfig = packageManager
    ? getPackageManagerCommands(packageManager)
    : getPackageManagerCommands("npm");
  const tokens = {
    DEV_URL: devUrl,
    PM_RUN: pmConfig.run, // e.g., "npm run", "bun run", "yarn", "pnpm run"
  };
  await saveConfig({
    tokens,
    stack: stack!,
    initialized: new Date().toISOString(),
  });
  configSpinner.succeed("Saved configuration");

  // Save multi-stack configuration if additional stacks selected
  if (additionalStacks.length > 0) {
    const stackConfig: StackConfigFile = {
      primary: { name: stack! },
      additional: additionalStacks.map((name) => ({ name })),
    };
    await saveStackConfig(stackConfig);
    console.log(chalk.blue("📋 Saved multi-stack configuration"));
  }

  // Create default settings
  const settingsSpinner = ui.spinner("Creating default settings...");
  settingsSpinner.start();
  await createDefaultSettings();
  settingsSpinner.succeed("Created default settings");

  // Detect codebase conventions
  const conventionsSpinner = ui.spinner("Detecting codebase conventions...");
  conventionsSpinner.start();
  try {
    const conventions = await detectAndSaveConventions(process.cwd());
    const count = Object.keys(conventions.detected).length;
    conventionsSpinner.succeed(`Detected ${count} codebase conventions`);
  } catch {
    conventionsSpinner.warn("Could not detect conventions (non-blocking)");
  }

  // Copy templates (with symlinks for scripts unless --no-symlinks)
  const templatesSpinner = ui.spinner("Copying templates...");
  templatesSpinner.start();
  const { scriptsSymlinked, symlinkResults } = await copyTemplates(
    stack!,
    tokens,
    {
      noSymlinks: options.noSymlinks,
      force: options.force,
      additionalStacks,
    },
  );

  templatesSpinner.succeed("Copied templates");

  // Report symlink status
  if (scriptsSymlinked) {
    ui.printStatus("success", "Created symlinks for scripts/dev/");
  } else if (!options.noSymlinks && symlinkResults) {
    // Some symlinks may have fallen back to copies
    const fallbacks = symlinkResults.filter((r) => r.fallbackToCopy);
    if (fallbacks.length > 0) {
      console.log(
        chalk.yellow("⚠️  Some scripts were copied instead of symlinked:"),
      );
      for (const fb of fallbacks) {
        console.log(chalk.gray(`   ${fb.path}: ${fb.reason}`));
      }
    }
    const skipped = symlinkResults.filter((r) => r.skipped);
    if (skipped.length > 0) {
      console.log(
        chalk.yellow("⚠️  Some scripts were skipped (existing files found):"),
      );
      for (const s of skipped) {
        console.log(chalk.gray(`   ${s.path}: ${s.reason}`));
      }
    }
  }

  // Create manifest
  const manifestSpinner = ui.spinner("Creating manifest...");
  manifestSpinner.start();
  await createManifest(stack!, packageManager ?? undefined);
  manifestSpinner.succeed("Created manifest");

  // Build optional suggestions section
  const optionalSuggestions = suggestions.filter((s) =>
    s.startsWith("Optional"),
  );
  const optionalSection =
    optionalSuggestions.length > 0
      ? `\n${chalk.bold("Optional improvements:")}\n${optionalSuggestions.map((s) => `  • ${s.replace("Optional: ", "")}`).join("\n")}\n`
      : "";

  // Build prerequisites reminder if there were remaining issues from wizard or warnings
  const hasRemainingIssues =
    wizardRemainingIssues.length > 0 || warnings.length > 0;
  const prereqReminder = hasRemainingIssues
    ? `\n${chalk.yellow("⚠️  Remember to install missing dependencies before using issue workflows.")}\n${chalk.gray("   Run 'sequant doctor' to verify your setup.\n")}`
    : "";

  // Success message with boxed output
  const nextStepsContent = `${chalk.bold("Next steps:")}
  1. Review .claude/memory/constitution.md
  2. Start using workflow commands:

     ${chalk.cyan("/spec 123")}  - Plan implementation
     ${chalk.cyan("/exec 123")}  - Implement the feature
     ${chalk.cyan("/qa 123")}    - Quality review`;

  console.log(
    "\n" + ui.successBox("Sequant initialized successfully!", nextStepsContent),
  );

  if (prereqReminder) {
    console.log(prereqReminder);
  }

  if (optionalSection) {
    console.log(optionalSection);
  }

  console.log(
    chalk.gray(
      "\nDocumentation: https://github.com/sequant-io/sequant#readme\n",
    ),
  );
}

#!/usr/bin/env node
/**
 * Sequant CLI - Quantize your development workflow
 *
 * Sequential AI phases with quality gates for any codebase.
 */

import { Command } from "commander";
import chalk from "chalk";
import { fileURLToPath } from "url";
import { dirname, resolve } from "path";
import { readFileSync } from "fs";
import { initCommand } from "../src/commands/init.js";
import { isLocalNodeModulesInstall } from "../src/lib/version-check.js";
import { configureUI, banner } from "../src/lib/cli-ui.js";
import { isCI, isStdoutTTY } from "../src/lib/tty.js";

// Read version from package.json dynamically
// Works from both source (bin/) and compiled (dist/bin/) locations
function getVersion(): string {
  const __dirname = dirname(fileURLToPath(import.meta.url));
  let dir = __dirname;
  while (dir !== dirname(dir)) {
    const candidate = resolve(dir, "package.json");
    try {
      const content = readFileSync(candidate, "utf-8");
      const pkg = JSON.parse(content);
      if (pkg.name === "sequant") {
        return pkg.version;
      }
    } catch {
      // Not found, continue searching
    }
    dir = dirname(dir);
  }
  return "0.0.0"; // Fallback
}
const version = getVersion();
import { updateCommand } from "../src/commands/update.js";
import { doctorCommand } from "../src/commands/doctor.js";
import { statusCommand } from "../src/commands/status.js";
import { runCommand } from "../src/commands/run.js";
import { logsCommand } from "../src/commands/logs.js";
import { statsCommand } from "../src/commands/stats.js";
import { dashboardCommand } from "../src/commands/dashboard.js";
import {
  stateInitCommand,
  stateRebuildCommand,
  stateCleanCommand,
} from "../src/commands/state.js";
import { syncCommand, areSkillsOutdated } from "../src/commands/sync.js";
import { mergeCommand } from "../src/commands/merge.js";
import { conventionsCommand } from "../src/commands/conventions.js";
import { getManifest } from "../src/lib/manifest.js";

const program = new Command();

// Handle --no-color before parsing
if (process.argv.includes("--no-color")) {
  process.env.FORCE_COLOR = "0";
}

// Configure UI early based on environment and flags
configureUI({
  noColor: process.argv.includes("--no-color") || !!process.env.NO_COLOR,
  jsonMode: process.argv.includes("--json"),
  verbose: process.argv.includes("--verbose") || process.argv.includes("-v"),
  isTTY: isStdoutTTY(),
  isCI: isCI(),
  minimal: process.env.SEQUANT_MINIMAL === "1",
});

// Warn if running from local node_modules (not npx cache or global)
// This helps users who accidentally have a stale local install
if (!process.argv.includes("--quiet") && isLocalNodeModulesInstall()) {
  console.warn(
    chalk.yellow(
      "⚠️  Running sequant from local node_modules\n" +
        "   For latest version: npx sequant@latest\n" +
        "   To remove local: npm uninstall sequant\n",
    ),
  );
}

program
  .name("sequant")
  .description(
    "Quantize your development workflow - Sequential AI phases with quality gates",
  )
  .version(version)
  .option("--no-color", "Disable colored output");

program
  .command("init")
  .description("Initialize Sequant in your project")
  .option("-s, --stack <stack>", "Specify stack (nextjs, rust, python, go)")
  .option("-y, --yes", "Skip confirmation prompts")
  .option("-f, --force", "Overwrite existing configuration")
  .option(
    "-i, --interactive",
    "Force interactive mode even in non-TTY environment",
  )
  .option("--skip-setup", "Skip the dependency setup wizard")
  .option(
    "--no-symlinks",
    "Use copies instead of symlinks for scripts/dev/ files",
  )
  .action(initCommand);

program
  .command("update")
  .description("Update templates from the Sequant package")
  .option("-d, --dry-run", "Show what would be updated without making changes")
  .option("-f, --force", "Overwrite local modifications")
  .action(updateCommand);

program
  .command("sync")
  .description(
    "Sync skills and templates from the Sequant package (non-interactive)",
  )
  .option("-f, --force", "Sync even if versions match")
  .option("-q, --quiet", "Suppress output")
  .action(syncCommand);

program
  .command("doctor")
  .description("Check your Sequant installation for issues")
  .option("--skip-issue-check", "Skip closed-issue verification check")
  .action(doctorCommand);

program
  .command("status")
  .description("Show Sequant version, configuration, and workflow state")
  .argument("[issue]", "Issue number to show details for", parseInt)
  .option("--issues", "Show all tracked issues")
  .option("--json", "Output as JSON")
  .option("--rebuild", "Rebuild state from run logs")
  .option("--cleanup", "Clean up stale/orphaned entries")
  .option("--dry-run", "Preview cleanup without changes")
  .option("--max-age <days>", "Remove entries older than N days", parseInt)
  .option("--all", "Remove all orphaned entries (merged and abandoned)")
  .action((issue, options) => {
    // Support positional arg: `sequant status 42` → --issue 42
    if (issue) {
      options.issue = issue;
    }
    return statusCommand(options);
  });

program
  .command("run")
  .description("Execute workflow for GitHub issues using Claude Agent SDK")
  .argument("[issues...]", "Issue numbers to process")
  .option("--phases <list>", "Phases to run (default: spec,exec,qa)")
  .option("--sequential", "Stop on first issue failure (default: continue)")
  .option("-d, --dry-run", "Preview without execution")
  .option("-v, --verbose", "Verbose output with streaming")
  .option("--timeout <seconds>", "Timeout per phase in seconds", parseInt)
  .option("--log-json", "Enable structured JSON logging (default: true)")
  .option("--no-log", "Disable JSON logging for this run")
  .option("--log-path <path>", "Custom log directory path")
  .option("-q, --quality-loop", "Enable quality loop with auto-retry")
  .option(
    "--max-iterations <n>",
    "Max iterations for quality loop (default: 3)",
    parseInt,
  )
  .option(
    "--batch <issues>",
    'Group of issues to run together (e.g., --batch "1 2" --batch "3")',
    (value: string, prev: string[]) => prev.concat([value]),
    [],
  )
  .option("--smart-tests", "Enable smart test detection (default)")
  .option("--no-smart-tests", "Disable smart test detection")
  .option("--testgen", "Run testgen phase after spec")
  .option("--quiet", "Suppress version warnings and non-essential output")
  .option(
    "--chain",
    "Chain issues: each branches from previous (implies --sequential)",
  )
  .option(
    "--qa-gate",
    "Wait for QA pass before starting next issue in chain (requires --chain)",
  )
  .option(
    "--base <branch>",
    "Base branch for worktree creation (default: main or settings.run.defaultBase)",
  )
  .option("--no-mcp", "Disable MCP server injection in headless mode")
  .option(
    "--no-retry",
    "Disable automatic retry with MCP fallback (useful for debugging)",
  )
  .option(
    "--resume",
    "Resume from last completed phase (reads phase markers from GitHub)",
  )
  .option(
    "--no-rebase",
    "Skip pre-PR rebase onto origin/main (use when you want to handle rebasing manually)",
  )
  .option(
    "--no-pr",
    "Skip PR creation after successful QA (manual PR workflow)",
  )
  .option(
    "-f, --force",
    "Force re-execution of completed issues (bypass pre-flight state guard)",
  )
  .option("--reflect", "Analyze run results and suggest improvements")
  .action(runCommand);

program
  .command("merge")
  .description(
    "Batch-level integration QA — verify feature branches before merging",
  )
  .argument(
    "[issues...]",
    "Issue numbers to check (auto-detects from most recent run if omitted)",
  )
  .option("--check", "Run Phase 1 deterministic checks (default)")
  .option("--scan", "Run Phase 1 + Phase 2 residual pattern detection")
  .option("--review", "Run Phase 1 + 2 + 3 AI briefing")
  .option("--all", "Run all phases")
  .option("--post", "Post report to GitHub as PR comments")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .action(mergeCommand);

program
  .command("conventions")
  .description("View and manage codebase conventions")
  .option("--detect", "Re-run convention detection")
  .option("--reset", "Clear detected conventions (keep manual)")
  .action(conventionsCommand);

program
  .command("logs")
  .description("View and analyze workflow run logs")
  .option("-p, --path <path>", "Custom log directory path")
  .option("-n, --last <n>", "Show last N runs", parseInt)
  .option("--json", "Output as JSON")
  .option("-i, --issue <number>", "Filter by issue number", parseInt)
  .option("--failed", "Show only failed runs")
  .option("--rotate", "Rotate logs (delete oldest to meet thresholds)")
  .option("-d, --dry-run", "Show what would be rotated without deleting")
  .action(logsCommand);

program
  .command("stats")
  .description("Show aggregate statistics for workflow runs")
  .option("-p, --path <path>", "Custom log directory path")
  .option("--csv", "Output as CSV")
  .option("--json", "Output as JSON")
  .action(statsCommand);

program
  .command("dashboard")
  .description("Start visual workflow dashboard in browser")
  .option("-p, --port <port>", "Port to run server on", parseInt)
  .option("--no-open", "Don't automatically open browser")
  .option("-v, --verbose", "Enable verbose logging")
  .action(dashboardCommand);

// State management command with subcommands
const stateCmd = program
  .command("state")
  .description("Manage workflow state for worktrees");

stateCmd
  .command("init")
  .description("Populate state for untracked worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .action(stateInitCommand);

stateCmd
  .command("rebuild")
  .description("Recreate state from logs and worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .option("-f, --force", "Force rebuild without confirmation")
  .action(stateRebuildCommand);

stateCmd
  .command("clean")
  .description("Remove entries for deleted worktrees")
  .option("--json", "Output as JSON")
  .option("-v, --verbose", "Enable verbose output")
  .option("-d, --dry-run", "Preview cleanup without changes")
  .option("--max-age <days>", "Remove entries older than N days", parseInt)
  .option("--all", "Remove all orphaned entries (merged and abandoned)")
  .action(stateCleanCommand);

// Auto-sync skills after npm upgrade (version mismatch detection)
// Only triggers when skills were previously synced (has .sequant-version marker).
// Projects that manage skills manually (no marker) are not affected.
program.hook("preAction", async (thisCommand) => {
  const cmd = thisCommand.name();
  if (cmd === "init" || cmd === "sync") return;

  const manifest = await getManifest();
  if (!manifest) return;

  const { outdated, currentVersion } = await areSkillsOutdated();
  if (outdated && currentVersion !== null) {
    await syncCommand({ quiet: true });
  }
});

// Parse and execute
program.parse();

// Show help if no command provided
if (!process.argv.slice(2).length) {
  console.log(banner());
  program.help();
}

