468→          : colors.error;
469→
470→    console.log(
471→      `  ${ui.statusIcon(statusType as "success" | "warning" | "error")} ${chalk.bold(check.name)}: ${color(check.message)}`,
472→    );
473→
474→    if (check.status === "pass") passCount++;
475→    else if (check.status === "warn") warnCount++;
476→    else failCount++;
477→  }
478→
479→  // Summary with boxed output
480→  const totalChecks = passCount + warnCount + failCount;
481→  let summaryTitle: string;
482→  let summaryMessage: string;
483→
484→  if (failCount > 0) {
485→    summaryTitle = `${failCount} check${failCount > 1 ? "s" : ""} failed`;
486→    summaryMessage = `Passed: ${passCount}/${totalChecks}\nWarnings: ${warnCount}\nFailed: ${failCount}\n\nRun \`sequant init\` to fix issues.`;
487→    console.log("\n" + ui.errorBox(summaryTitle, summaryMessage));
488→    process.exit(1);
489→  } else if (warnCount > 0) {
490→    summaryTitle = `All checks passed (${warnCount} warning${warnCount > 1 ? "s" : ""})`;
491→    summaryMessage = `Passed: ${passCount}/${totalChecks}\nWarnings: ${warnCount}\n\nSequant should work correctly.`;
492→    console.log("\n" + ui.warningBox(summaryTitle, summaryMessage));
493→  } else {
494→    summaryTitle = `All ${totalChecks} checks passed!`;
495→    summaryMessage = `Your Sequant installation is healthy.`;
496→    console.log("\n" + ui.successBox(summaryTitle, summaryMessage));
497→  }
498→}
