/**
 * File system utilities
 */

import {
  access,
  constants,
  mkdir,
  readFile as fsReadFile,
  writeFile as fsWriteFile,
  stat,
  lstat,
  symlink,
  unlink,
  readlink,
} from "fs/promises";
import { dirname } from "path";

export async function fileExists(path: string): Promise<boolean> {
  try {
    await access(path, constants.F_OK);
    return true;
