// Mock system functions
vi.mock("../lib/system.js", () => ({
  commandExists: vi.fn(),
  isGhAuthenticated: vi.fn(),
  isNativeWindows: vi.fn(),
  isWSL: vi.fn(),
  checkOptionalMcpServers: vi.fn(),
  getMcpServersConfig: vi.fn(),
  OPTIONAL_MCP_SERVERS: [
