      expect(processExitSpy).not.toHaveBeenCalled();
    });

    it("does not fail when MCPs are missing (they are optional)", async () => {
      mockCheckOptionalMcpServers.mockReturnValue({
        "chrome-devtools": false,
        context7: false,
        "sequential-thinking": false,
