      expect(output).toContain(
        "https://docs.anthropic.com/en/docs/claude-code",
      );
    });
  });

  describe("jq checks", () => {
    it("passes when jq is installed", async () => {
      mockCommandExists.mockReturnValue(true);
      mockIsGhAuthenticated.mockReturnValue(true);

      await doctorCommand();

